INSERT INTO `yzm_poetry` (`title`, `author`, `dynasty`, `type`, `content`, `theme`, `interpretation`, `appreciation`, `create_time`) VALUES

-- 唐诗
('望庐山瀑布', '李白', '唐', 1, '日照香炉生紫烟，遥看瀑布挂前川。飞流直下三千尺，疑是银河落九天。', '山水', '太阳照射的香炉峰升起紫色烟雾，远远望去瀑布像挂在山前一样。水流从三千尺高处飞流而下，让人怀疑是银河从天上落到人间。', '这首诗形象地描绘了庐山瀑布的壮观景象，运用夸张手法表现了瀑布的气势。', UNIX_TIMESTAMP()),
('黄鹤楼送孟浩然之广陵', '李白', '唐', 1, '故人西辞黄鹤楼，烟花三月下扬州。孤帆远影碧空尽，唯见长江天际流。', '送别', '老朋友向我辞别黄鹤楼，在这烟花三月前往扬州。孤独的帆船和远去的影子在碧空中渐渐消失，只见长江水向天边流去。', '这首诗情景交融，以景写情，表达了诗人对友人的深厚情谊。', UNIX_TIMESTAMP()),
('将进酒', '李白', '唐', 1, '君不见黄河之水天上来，奔流到海不复回。君不见高堂明镜悲白发，朝如青丝暮成雪。人生得意须尽欢，莫使金樽空对月。天生我材必有用，千金散尽还复来。', '励志', '你难道没看见黄河的水从天上倾泻而下，奔流到海不再回来。你难道没看见高堂上的人对着镜子悲叹白发，早上还是青丝晚上就变成雪白。人生得意时要尽情欢乐，不要让酒杯空对着月光。老天赋予我才能必定有用，千金花光了还会再回来。', '这首诗表达了诗人乐观豪放的人生态度和对自己才华的自信。', UNIX_TIMESTAMP()),
('望月怀远', '张九龄', '唐', 1, '海上生明月，天涯共此时。情人怨遥夜，竟夕起相思。灭烛怜光满，披衣觉露滋。不堪盈手赠，还寝梦佳期。', '思念', '海上升起一轮明月，远在天涯的人此时也在望月思念。有情之人埋怨长夜漫漫，整夜都在相思。吹灭蜡烛喜爱这满室月光，披上衣服感到露水湿润。不能捧一把月光赠送给你，不如回去在梦中与你相会。', '这首诗借望月表达了对远方亲人的深切思念。', UNIX_TIMESTAMP()),
('春望', '杜甫', '唐', 1, '国破山河在，城春草木深。感时花溅泪，恨别鸟惊心。烽火连三月，家书抵万金。白头搔更短，浑欲不胜簪。', '爱国', '国家破碎但山河依旧存在，春天城里草木茂盛。感伤时事看到花开反而落泪，怨恨离别听到鸟鸣更惊心。战火连续三个月不断，一封家书抵得上万两黄金。头发白了越搔越短，简直连簪子都插不上了。', '这首诗表达了诗人忧国忧民的情怀。', UNIX_TIMESTAMP()),
('茅屋为秋风所破歌', '杜甫', '唐', 1, '八月秋高风怒号，卷我屋上三重茅。茅飞渡江洒江郊，高者挂罥长林梢，下者飘转沉塘坳。', '生活', '八月秋深狂风怒号，卷走我屋上三层茅草。茅草飞过江去洒在江边，高的挂在树林梢上，低的飘转沉入池塘。', '这首诗描写了诗人贫困的生活和坚韧的性格。', UNIX_TIMESTAMP()),
('山居秋暝', '王维', '唐', 1, '空山新雨后，天气晚来秋。明月松间照，清泉石上流。竹喧归浣女，莲动下渔舟。随意春芳歇，王孙自可留。', '山水', '空旷的山中刚下过雨，秋天的傍晚天气凉爽。明月在松林间照耀，清澈的泉水在石上流淌。竹林喧响是洗衣的女子归来，莲叶摇动是渔船靠岸。任凭春天的芳菲消散，隐居的人自然可以长留。', '这首诗描绘了秋山雨后的优美景色，表达了诗人对隐居生活的向往。', UNIX_TIMESTAMP()),
('鸟鸣涧', '王维', '唐', 1, '人闲桂花落，夜静春山空。月出惊山鸟，时鸣春涧中。', '山水', '人闲静的时候桂花轻轻飘落，春夜的山林更加空寂。月亮升起惊动了山鸟，不时在春天的溪涧中鸣叫。', '这首诗以动写静，通过花落、鸟鸣来反衬春山的寂静。', UNIX_TIMESTAMP()),
('相思', '王维', '唐', 1, '红豆生南国，春来发几枝。愿君多采撷，此物最相思。', '思念', '红豆生长在南方，春天来了发了几枝。希望你多采摘一些，这东西最能寄托相思之情。', '这首诗借红豆寄托相思，语言清新，感情真挚。', UNIX_TIMESTAMP()),
('九月九日忆山东兄弟', '王维', '唐', 1, '独在异乡为异客，每逢佳节倍思亲。遥知兄弟登高处，遍插茱萸少一人。', '思乡', '独自在他乡作客，每到佳节更加思念亲人。远远想到兄弟们登高的地方，个个插着茱萸却少了我一人。', '这首诗表达了诗人深切的思乡之情。', UNIX_TIMESTAMP()),
('出塞', '王昌龄', '唐', 1, '秦时明月汉时关，万里长征人未还。但使龙城飞将在，不教胡马度阴山。', '边塞', '秦时明月照着汉时的边关，万里长征的将士还未归还。如果有龙城飞将军李广在，绝不会让胡人的马越过阴山。', '这首诗表达了诗人对英勇将士的崇敬和报国之志。', UNIX_TIMESTAMP()),
('芙蓉楼送辛渐', '王昌龄', '唐', 1, '寒雨连江夜入吴，平明送客楚山孤。洛阳亲友如相问，一片冰心在玉壶。', '送别', '寒冷的雨连夜洒满江面清晨来到吴地，送客时楚山显得那么孤独。如果洛阳的亲友问起我，就说我的心像冰在玉壶中一样纯洁。', '这首诗以冰心玉壶表达诗人高洁的品格。', UNIX_TIMESTAMP()),
('凉州词', '王翰', '唐', 1, '葡萄美酒夜光杯，欲饮琵琶马上催。醉卧沙场君莫笑，古来征战几人回。', '边塞', '精美的夜光杯中盛着葡萄美酒，正要饮酒时马上的琵琶声催促。醉倒在沙场上请你不要笑，自古以来出征的人有几个能回来。', '这首诗表达了边塞将士的豪迈气概和视死如归的精神。', UNIX_TIMESTAMP()),
('出塞', '王之涣', '唐', 1, '黄河远上白云间，一片孤城万仞山。羌笛何须怨杨柳，春风不度玉门关。', '边塞', '黄河远远流淌直上白云之间，一座孤城坐落在万仞山之中。何必用羌笛吹奏《折杨柳》抱怨春天不来，玉门关外春风都吹不到。', '这首诗描写了边塞的苍凉景象，表达了戍边战士的思乡之情。', UNIX_TIMESTAMP()),
('凉州词', '王之涣', '唐', 1, '白日依山尽，黄河入海流。欲穷千里目，更上一层楼。', '励志', '太阳靠着山峦渐渐沉落，黄河朝着大海奔流。想要看得更远，就要再登上一层楼。', '这首诗意境开阔，表达了积极向上的精神。', UNIX_TIMESTAMP()),

-- 宋词
('水调歌头·明月几时有', '苏轼', '宋', 2, '明月几时有？把酒问青天。不知天上宫阙，今夕是何年。我欲乘风归去，又恐琼楼玉宇，高处不胜寒。起舞弄清影，何似在人间。转朱阁，低绮户，照无眠。不应有恨，何事长向别时圆？人有悲欢离合，月有阴晴圆缺，此事古难全。但愿人长久，千里共婵娟。', '思念', '明月什么时候才有？我端起酒杯问青天。不知道天上的宫殿，今晚是何年何月。我想乘风回去，又担心美玉砌成的楼阁，受不住高处的寒冷。在月下起舞，清影翩翩，哪里比得上人间。月亮转动着，照过朱红楼阁，低低地挂在雕花窗上，照着不能入睡的人。不应该有遗憾，为什么常常在分别时才圆呢？人有悲欢离合，月有阴晴圆缺，这种事自古以来就难以周全。只希望人能平安长久，千里之外共同欣赏这轮明月。', '这首词借月抒怀，表达了诗人旷达的胸襟和对亲人的美好祝愿。', UNIX_TIMESTAMP()),
('念奴娇·赤壁怀古', '苏轼', '宋', 2, '大江东去，浪淘尽，千古风流人物。故垒西边，人道是，三国周郎赤壁。乱石穿空，惊涛拍岸，卷起千堆雪。江山如画，一时多少豪杰。遥想公瑾当年，小乔初嫁了，雄姿英发。羽扇纶巾，谈笑间，樯橹灰飞烟灭。故国神游，多情应笑我，早生华发。人生如梦，一尊还酹江月。', '怀古', '长江水浩浩荡荡向东流去，浪花淘尽了千古风流人物。那旧营垒的西边，人们说那是三国周瑜大破曹兵的赤壁。陡峭的石壁直插云天，惊涛骇浪拍打着江岸，卷起千堆雪。江山美丽如画，一时涌现多少英雄豪杰。遥想周瑜当年，小乔刚嫁过来，英姿勃勃。手摇羽扇，头戴纶巾，谈笑间曹军战船灰飞烟灭。神游故国，应该笑我多情善感，头发早白。人生像一场梦，还是举起酒杯祭奠江月吧。', '这首词借古讽今，表达了诗人壮志难酬的感慨。', UNIX_TIMESTAMP()),
('江城子·密州出猎', '苏轼', '宋', 2, '老夫聊发少年狂，左牵黄，右擎苍，锦帽貂裘，千骑卷平冈。为报倾城随太守，亲射虎，看孙郎。酒酣胸胆尚开张，鬓微霜，又何妨！持节云中，何日遣冯唐？会挽雕弓如满月，西北望，射天狼。', '励志', '老夫我姑且抒发一下少年人的狂放，左手牵着黄狗，右臂举着苍鹰，头戴锦帽身穿貂裘，率领千骑席卷山冈。为了报答全城的人都跟随我出猎，我要像孙权一样亲自射虎。酒喝得正畅快，胸怀胆量也豪壮，鬓角白了又有什么关系！什么时候能像冯唐那样手持符节云中郡去赦免魏尚？到那时我拉满雕弓如圆月，向西北望去，射杀天狼星。', '这首词表达了词人报效国家的壮志豪情。', UNIX_TIMESTAMP()),
('蝶恋花', '欧阳修', '宋', 2, '庭院深深深几许，杨柳堆烟，帘幕无重数。玉勒雕鞍游冶处，楼高不见章台路。雨横风狂三月暮，门掩黄昏，无计留春住。泪眼问花花不语，乱红飞过秋千去。', '闺怨', '庭院深深不知道有多深，杨柳如烟笼罩，帘幕重重无数。装饰华贵的马车停在游乐之处，高楼却望不见章台路。三月暮春雨暴风狂，黄昏时掩上门，无法留住春天。含泪问花，花不说话，零乱的落红飞过秋千去。', '这首词描写了闺怨之情，情景交融，委婉动人。', UNIX_TIMESTAMP()),
('雨霖铃', '柳永', '宋', 2, '寒蝉凄切，对长亭晚，骤雨初歇。都门帐饮无绪，留恋处，兰舟催发。执手相看泪眼，竟无语凝噎。念去去，千里烟波，暮霭沉沉楚天阔。多情自古伤离别，更那堪，冷落清秋节！今宵酒醒何处？杨柳岸，晓风残月。此去经年，应是良辰好景虚设。便纵有千种风情，更与何人说？', '离别', '寒蝉叫声凄凉悲切，面对长亭已是傍晚，骤雨刚刚停歇。在京城门外设帐饯行却没有心情，正留恋时，船夫已催促出发。握着手相互看着泪眼，竟然哽咽着说不出话。想到此去千里烟波，暮色沉沉楚天广阔。自古多情的人就为离别悲伤，更哪能忍受这冷落的清秋节。今夜酒醒时会在哪里？杨柳岸边，晨风习习残月。要这一去就是一年，良辰美景形同虚设。就算有千种风情，又能跟谁说呢？', '这首词是离别词的代表作，情景交融，感人至深。', UNIX_TIMESTAMP()),
('望海潮', '柳永', '宋', 2, '东南形胜，三吴都会，钱塘自古繁华。烟柳画桥，风帘翠幕，参差十万人家。云树绑堤沙，怒涛卷霜雪，天堑无涯。市列珠玑，户盈罗绮，竟豪奢。重湖叠巘清嘉，有三秋桂子，十里荷花。羌管弄晴，菱歌泛夜，嬉嬉钓叟莲娃。千骑拥高牙，乘醉听箫鼓，吟赏烟霞。异日图将好景，归去凤池夸。', '风景', '东南地理位置重要，是三吴的重要都市，钱塘自古以来就繁华。烟霭中的柳树装饰着彩桥，风帘翠幕，住了约十万户人家。云雾笼罩的钱塘江堤，怒涛卷起霜雪，天然的壕沟广阔无边。市场上陈列着珍珠宝石，每户都堆满了绫罗绸缎，真是豪奢。重湖叠嶂清秀美好，有三秋的桂花，十里的荷花。晴天吹奏羌笛，夜晚划船采菱角，快乐的钓翁和采莲女。高牙大旗飘扬，乘着醉意听箫声鼓点，吟诗欣赏烟霞。他日把这美景画下来，回到京城凤凰池去夸耀。', '这首词描写了杭州的繁华和美丽，词藻华丽。', UNIX_TIMESTAMP()),
('满江红', '岳飞', '宋', 2, '怒发冲冠，凭栏处、潇潇雨歇。抬望眼，仰天长啸，壮怀激烈。三十功名尘与土，八千里路云和月。莫等闲、白了少年头，空悲切！靖康耻，犹未雪。臣子恨，何时灭！驾长车，踏破贺兰山缺。壮志饥餐胡虏肉，笑谈渴饮匈奴血。待从头、收拾旧山河，朝天阙。', '爱国', '愤怒得头发冲上帽子，靠着栏杆外面雨刚停。抬头远望，对着天空大声呼啸，壮烈的胸怀激烈。三十年功名像尘土与土一样微小，八千里路途披星戴月。不要虚度年华，不然白了少年头，只能独自悲切。靖康年的耻辱，还没有洗雪。臣子的愤恨，什么时候才能消灭！驾着战车，踏破贺兰山缺口。满怀壮志要吃敌人的肉，谈笑间渴了喝敌人的血。等到重新收拾好旧山河，再去朝见皇帝。', '这首词表达了岳飞的爱国精神和报国之志。', UNIX_TIMESTAMP()),
('渔家傲·秋思', '范仲淹', '宋', 2, '塞下秋来风景异，衡阳雁去无留意。四面边声连角起，千嶂里，长烟落日孤城闭。浊酒一杯家万里，燕然未勒归无计。羌管悠悠霜满地，人不寐，将军白发征夫泪。', '边塞', '边塞的秋天风景不同，大雁飞往衡阳毫无留恋。四面边塞的声音连同号角声响起，千山万岭中，炊烟升腾夕阳西沉，孤零零的城门紧闭。喝一杯浊酒思念万里之外的家乡，燕然山还未刻石记功，无法考虑回去。羌笛悠扬白霜满地，睡不着觉，将军白了头发，士兵流下眼泪。', '这首词描写了边塞生活的艰苦和思乡之情。', UNIX_TIMESTAMP()),
('青玉案·元夕', '辛弃疾', '宋', 2, '东风夜放花千树，更吹落、星如雨。宝马雕车香满路。凤箫声动，玉壶光转，一夜鱼龙舞。蛾儿雪柳黄金缕，笑语盈盈暗香去。众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。', '元宵', '东风吹开千树繁花，更吹落星星如雨点。宝马雕花车香气充满道路。凤箫声悠扬，玉壶灯光流转，鱼灯龙灯飞舞。姑娘们头上插着蛾儿雪柳，笑语盈盈香气随风飘去。在人群中找了她千百次，忽然回头，她却在灯火稀疏的地方。', '这首词描写了元宵佳节的热闹景象，结尾表达了词人对理想的追求。', UNIX_TIMESTAMP()),
('破阵子·为陈同甫赋壮词以寄', '辛弃疾', '宋', 2, '醉里挑灯看剑，梦回吹角连营。八百里分麾下炙，五十弦翻塞外声，沙场秋点兵。马作的卢飞快，弓如霹雳弦惊。了却君王天下事，赢得生前身后名。可怜白发生！', '励志', '酒醉中挑亮灯芯看剑，梦里回到连营。八百里的军营中分发给部下烤肉，五十弦乐器奏出塞外的歌声，秋天在沙场点兵。战马像的卢一样飞快，弓箭如霹雳般震响。了结君王统一天下的大事，赢得身前身后的英名。可怜头发已经白了！', '这首词表达了词人壮志未酬的悲愤。', UNIX_TIMESTAMP()),
('卜算子·咏梅', '陆游', '宋', 2, '驿外断桥边，寂寞开无主。已是黄昏独自愁，更著风和雨。无意苦争春，一任群芳妒。零落成泥碾作尘，只有香如故。', '咏物', '驿站外断桥边，寂寞地开放没有人欣赏。已是黄昏独自忧愁，又加上风吹雨打。不想刻意争春，任凭百花嫉妒。凋零飘落变成泥土碾成灰尘，只有香气还和从前一样。', '这首词借梅花表达了词人高洁的品格和坚贞的意志。', UNIX_TIMESTAMP()),
('游山西村', '陆游', '宋', 2, '莫笑农家腊酒浑，丰年留客足鸡豚。山重水复疑无路，柳暗花明又一村。箫鼓追随春社近，衣冠简朴古风存。从今若许闲乘月，拄杖无时夜叩门。', '田园', '不要笑农家腊月酿的酒浑浊，丰收年景留客的饭菜足够鸡肉猪肉。山岭重叠水流曲折似乎无路可走，柳绿花艳又出现一个村庄。吹箫打鼓跟着春社的日子近了，穿着朴素的古风还存在。从今以后如果能得闲乘月而来，我会拄着拐杖随时在夜里敲门拜访。', '这首诗描写了田园风光和淳朴的民风。', UNIX_TIMESTAMP()),
('示儿', '陆游', '宋', 2, '死去元知万事空，但悲不见九州同。王师北定中原日，家祭无忘告乃翁。', '爱国', '本来就知道死了就什么都是空的，只是悲伤看不到祖国统一。等朝廷的军队北伐平定中原的时候，祭拜时不要忘了告诉你父亲。', '这首诗是陆游的绝笔诗，表达了他至死不渝的爱国情怀。', UNIX_TIMESTAMP()),
('一剪梅', '李清照', '宋', 2, '红藕香残玉簟秋。轻解罗裳，独上兰舟。云中谁寄锦书来？雁字回时，月满西楼。花自飘零水自流。一种相思，两处闲愁。此情无计可消除，才下眉头，却上心头。', '相思', '红藕香残玉簟发凉秋天。轻轻解开绫罗裙，独自登上木兰舟。云中谁寄来了书信？雁群飞回时，月光洒满西楼。花儿独自飘落水自然流。一种相思，两处闲愁。这种情绪没有办法消除，才从眉头上消失，却涌上心头。', '这首词表达了词人对远方亲人的深切思念。', UNIX_TIMESTAMP()),
('声声慢', '李清照', '宋', 2, '寻寻觅觅，冷冷清清，凄凄惨惨戚戚。乍暖还寒时候，最难将息。三杯两盏淡酒，怎敌他、晚来风急！雁过也，正伤心，却是旧时相识。满地黄花堆积，憔悴损，如今有谁堪摘？守着窗儿，独自怎生得黑！梧桐更兼细雨，到黄昏、点点滴滴。这次第，怎一个愁字了得！', '闺怨', '四处寻觅，环境冷清，凄凉悲惨。正当天气忽暖忽寒的时候，最难调养身体。喝几杯淡酒，怎么抵挡得了晚上急促的风！大雁飞过，正令人伤心，却是旧日相识。满地菊花堆积，憔悴损，如今有谁来摘？守着窗户，独自怎么熬到天黑！梧桐叶加上细雨，到黄昏时点点滴滴。这种情形，怎么是一个愁字能概括的！', '这首词情景交融，表达了词人晚年的孤独和凄凉。', UNIX_TIMESTAMP()),

-- 诗经
('蒹葭', '诗经', '先秦', 3, '蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。蒹葭采采，白露未已，所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在水中沚。', '爱情', '河边芦苇青苍苍，露水凝结成霜。我所怀念的心上人啊，就在对岸那一边。', '这是一首著名的爱情诗，描写了对意中人的思念和追求。', UNIX_TIMESTAMP()),
('关雎', '诗经', '先秦', 3, '关关雎鸠，在河之洲。窈窕淑女，君子好逑。参差荇菜，左右流之。窈窕淑女，寤寐求之。求之不得，寤寐思服。悠哉悠哉，辗转反侧。参差荇菜，左右采之。窈窕淑女，琴瑟友之。参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。', '爱情', '雎鸠鸟在河中小岛上关关和鸣，美丽贤淑的女子，是君子的好配偶。', '这是《诗经》的开篇之作，描写了青年男子对美丽女子的追求。', UNIX_TIMESTAMP()),
('子衿', '诗经', '先秦', 3, '青青子衿，悠悠我心。纵我不往，子宁不嗣音？青青子佩，悠悠我思。纵我不往，子宁不来？挑兮达兮，在城阙兮。一日不见，如三月兮。', '思念', '你的衣领青又青，我心思念长又长。纵然我不能去，你怎能断了音信？', '这首诗表达了女子对情人的思念。', UNIX_TIMESTAMP()),
('木瓜', '诗经', '先秦', 3, '投我以木瓜，报之以琼琚。匪报也，永以为好也！投我以木桃，报之以琼瑶。匪报也，永以为好也！投我以木李，报之以琼玖。匪报也，永以为好也！', '爱情', '你送给我木瓜，我用美玉回报。不是为了报答，是要永远相好！', '这首诗表达了真挚的爱情。', UNIX_TIMESTAMP()),
('采葛', '诗经', '先秦', 3, '彼采葛兮，一日不见，如三月兮！彼采萧兮，一日不见，如三秋兮！采艾兮，一日不见，如三岁兮！', '思念', '那个采葛的人啊，一天不见，像过了三个月。那个采萧的人啊，一天不见，像过了三季。那个采艾的人啊，一天不见，像过了三年。', '这首诗表达了思念之情。', UNIX_TIMESTAMP()),

-- 楚辞
('离骚', '屈原', '先秦', 4, '帝高阳之苗裔兮，朕皇考曰伯庸。摄提贞于孟陬兮，惟庚寅以降兮。皇览揆余初度兮，肇锡余以嘉名：名余曰正则兮，字余曰灵均。', '爱国', '我是古帝高阳氏的后代，我的父亲字伯庸。', '屈原的代表作，表达了他忠君爱国的思想。', UNIX_TIMESTAMP()),
('九歌·东皇太一', '屈原', '先秦', 4, '吉日兮辰良，穆将愉兮上皇。抚长剑兮玉珥，璆锵鸣兮琳琅。', '祭祀', '吉祥的日子美好的时光，恭敬地娱悦东皇太一。', '这是屈原祭祀东皇太一的祭歌。', UNIX_TIMESTAMP()),
('九歌·湘君', '屈原', '先秦', 4, '君不行兮夷犹，蹇谁留兮中洲？美要眇兮宜修，沛吾乘兮桂舟。令沅湘兮无波，使江水兮安流！', '爱情', '你犹豫不前是为谁停留在水中小洲？我修饰得美丽得体，乘着桂木船漂流。', '这首诗描写了湘夫人对湘君的思念。', UNIX_TIMESTAMP()),
('九歌·山鬼', '屈原', '先秦', 4, '若有人兮山之阿，被薜荔兮带女萝。既含睇兮又宜笑，子慕予兮善窈窕。', '神话', '仿佛有人站在山坳，身披薜荔腰束女萝。含情凝视巧笑美丽，你爱慕我姿态窈窕。', '这首诗描写了山鬼的形象和情感。', UNIX_TIMESTAMP()),
('涉江', '屈原', '先秦', 4, '余幼好此奇服兮，年既老而不衰。带长铗之陆离兮，冠切云之崔嵬。被明月兮珮宝璐。', '志向', '我自幼就爱好这奇异的服饰啊，年纪虽老而兴致不减。', '这首诗表达了屈原的高尚志向。', UNIX_TIMESTAMP()),

-- 名句摘录
('劝学', '颜真卿', '唐', 1, '三更灯火五更鸡，正是男儿读书时。黑发不知勤学早，白首方悔读书迟。', '励志', '三更挑灯五更鸡鸣，正是男儿读书的时候。年少时不知道勤奋学习，到白发苍苍才后悔读书太迟。', '这首诗劝勉年轻人珍惜时光，勤奋学习。', UNIX_TIMESTAMP()),
('悯农', '李绅', '唐', 1, '锄禾日当午，汗滴禾下土。谁知盘中餐，粒粒皆辛苦。', '生活', '农民在烈日下锄禾，汗水滴落在禾苗下的土里。谁知道盘中的饭食，每一粒都包含着农民的辛苦。', '这首诗表达了诗人对农民辛苦劳动的同情。', UNIX_TIMESTAMP()),
('悯农', '李绅', '唐', 1, '春种一粒粟，秋收万颗子。四海无闲田，农夫犹饿死。', '生活', '春天种下一粒种子，秋天收获万颗谷子。四海之内没有荒废的田地，但农夫还是饿死了。', '这首诗揭露了封建社会农民的悲惨命运。', UNIX_TIMESTAMP()),
('回乡偶书', '贺知章', '唐', 1, '少小离家老大回，乡音无改鬓毛衰。儿童相见不相识，笑问客从何处来。', '思乡', '少年时离开家乡老了才回来，乡音没有改变但两鬓斑白。孩子们见了我都不认识，笑着问客人从哪里来。', '这首诗表达了诗人深深的思乡之情。', UNIX_TIMESTAMP()),
('咏柳', '贺知章', '唐', 1, '碧玉妆成一树高，万条垂下绿丝绦。不知细叶谁裁出，二月春风似剪刀。', '咏物', '高高的柳树像碧玉妆扮成，万条下垂像绿色的丝带。不知道这细叶是谁裁出，二月的春风像剪刀一样。', '这首诗赞美了柳树的美丽和春天的造化之功。', UNIX_TIMESTAMP()),
('清明', '杜牧', '唐', 1, '清明时节雨纷纷，路上行人欲断魂。借问酒家何处有，牧童遥指杏花村。', '节日', '清明时节细雨纷纷，路上远行的人失魂落魄。打听哪里有酒家，牧童远远地指向杏花村。', '这首诗描写了清明时节的景象和行人的心情。', UNIX_TIMESTAMP()),
('山行', '杜牧', '唐', 1, '远上寒山石径斜，白云生处有人家。停车坐爱枫林晚，霜叶红于二月花。', '山水', '远远登上寒山石路弯斜，白云生长的地方有几户人家。停下马车是因为喜爱这傍晚的枫林，霜打过的枫叶比二月的花还红。', '这首诗描写了秋山景色的美丽。', UNIX_TIMESTAMP()),
('江南春', '杜牧', '唐', 1, '千里莺啼绿映红，水村山郭酒旗风。南朝四百八十寺，多少楼台烟雨中。', '山水', '千里江南黄莺啼叫绿树红花相映，水边村庄山边城郭酒旗在风中飘扬。', '这首诗描写了江南春天的美丽景色。', UNIX_TIMESTAMP()),
('泊秦淮', '杜牧', '唐', 1, '烟笼寒水月笼沙，夜泊秦淮近酒家。商女不知亡国恨，隔江犹唱后庭花。', '怀古', '烟雾笼罩寒江月笼罩白沙，夜晚停泊在秦淮河靠近酒家。商女不知道亡国的怨恨，隔江还在唱着《后庭花》。', '这首诗借古讽今，表达了诗人对国家命运的忧虑。', UNIX_TIMESTAMP()),
('乌衣巷', '刘禹锡', '唐', 1, '朱雀桥边野草花，乌衣巷口夕阳斜。旧时王谢堂前燕，飞入寻常百姓家。', '怀古', '朱雀桥边长着野草野花，乌衣巷口夕阳西斜。从前在王导谢安家堂前的燕子，现在飞进了普通百姓家。', '这首诗通过燕子归宿的变化，表达了世事变迁的感慨。', UNIX_TIMESTAMP()),
('竹枝词', '刘禹锡', '唐', 1, '杨柳青青江水平，闻郎江上唱歌声。东边日出西边雨，道是无晴却有晴。', '爱情', '杨柳青翠江水平静，听到情郎在江上唱歌。杨柳如烟歌声嘹亮，东边日出西边下雨，说是没晴却又有晴。', '这首诗描写了青年男女的爱情。', UNIX_TIMESTAMP()),
('望洞庭', '刘禹锡', '唐', 1, '湖光秋月两相和，潭面无风镜未磨。遥望洞庭山水翠，白云生处有人家。', '山水', '湖水和秋月交相辉映，潭面平静像没有磨过的镜子。远远望去洞庭湖山水翠绿，白云升起的地方有几户人家。', '这首诗描写了洞庭湖的美丽景色。', UNIX_TIMESTAMP()),
('赋得古原草送别', '白居易', '唐', 1, '离离原上草，一岁一枯荣。野火烧不尽，春风吹又生。远芳侵古道，晴翠接荒城。又送王孙去，萋萋满别情。', '送别', '古原上的草繁茂旺盛，一年一度枯萎又繁荣。野火烧不完它，春风一吹它又生长。伸向远方蔓延到古道，晴日下翠绿连接荒城。又送您这远方的人，满怀着离别之情。', '这首诗以草喻情，表达了深厚的友情。', UNIX_TIMESTAMP()),
('忆江南', '白居易', '唐', 1, '江南好，风景旧曾谙。日出江花红胜火，春来江水绿如蓝。能不忆江南？', '风景', '江南的风景我曾经很熟悉。太阳出来江花红得像火，春天来临江水绿得像蓝草。怎么能不怀念江南？', '这首诗赞美了江南的美丽风光。', UNIX_TIMESTAMP()),
('暮江吟', '白居易', '唐', 1, '一道残阳铺水中，半江瑟瑟半江红。可怜九月初三夜，露似真珠月似弓。', '风景', '一道残阳铺展在江面上，半江碧绿半江鲜红。可爱的九月初三夜晚，露水像珍珠月亮像弯弓。', '这首诗描写了傍晚江上的美丽景色。', UNIX_TIMESTAMP()),
('题都城南庄', '崔护', '唐', 1, '去年今日此门中，人面桃花相映红。人面不知何处去，桃花依旧笑春风。', '爱情', '去年今天在这扇门里，姑娘的脸和桃花相映红。不知道姑娘到哪里去了，桃花依旧在春风中盛开。', '这首诗表达了物是人非的感慨。', UNIX_TIMESTAMP()),
('枫桥夜泊', '张继', '唐', 1, '月落乌啼霜满天，江枫渔火对愁眠。姑苏城外寒山寺，夜半钟声到客船。', '思乡', '月亮落下乌鸦啼叫满天霜华，江边枫树渔火相对引起客愁。苏州城外寒山寺，半夜钟声传到客船。', '这首诗表达了诗人的思乡之情。', UNIX_TIMESTAMP()),
('滁州西涧', '韦应物', '唐', 1, '独怜幽草涧边生，上有黄鹂深树鸣。春潮带雨晚来急，野渡无人舟自横。', '山水', '最喜爱涧边幽静生长的草，上面有黄鹂在深树中啼叫。春潮带着雨在晚上更急，野外渡口没有人船自己横着。', '这首诗描写了西涧的幽静景色。', UNIX_TIMESTAMP()),
('寒食', '韩翃', '唐', 1, '春城无处不飞花，寒食东风御柳斜。日暮汉宫传蜡烛，轻烟散入五侯家。', '节日', '春天的长安城无处不飘花，寒食节东风吹得宫柳歪斜。黄昏时汉宫传送蜡烛，淡淡的烟散入权贵人家。', '这首诗描写了寒食节的景象。', UNIX_TIMESTAMP()),
('早春呈水部张十八员外', '韩愈', '唐', 1, '天街小雨润如酥，草色遥看近却无。最是一年春好处，绝胜烟柳满皇都。', '风景', '长安街上细雨润滑如酥，远看草色青青近看却没有。一年最好的就是早春时节，远远胜过烟柳笼罩的京城。', '这首诗赞美了早春的景色。', UNIX_TIMESTAMP()),
('晚春', '韩愈', '唐', 1, '草树知春不久归，百般红紫斗芳菲。杨花榆荚无才思，惟解漫天作雪飞。', '风景', '花草树木知道春天不久就要回去，万紫千红竞相争艳。杨花榆荚没有才华，只会像雪一样漫天飞舞。', '这首诗描写了晚春的景象。', UNIX_TIMESTAMP()),
('题李凝幽居', '贾岛', '唐', 1, '闲居少邻并，草径入荒园。鸟宿池边树，僧敲月下门。过桥分野色，移石动云根。暂去还来此，幽期不负言。', '田园', '悠闲地居住少有邻居，杂草丛生的小径通入荒园。鸟在池边树上栖息，僧人在月下敲门。走过桥去原野分成不同景色，白云飘动仿佛在移动山石。暂时离去还会回来，不负幽雅的约定。', '这首诗描写了幽居的清静环境。', UNIX_TIMESTAMP()),
('题李凝幽居', '贾岛', '唐', 1, '松下问童子，言师采药去。只在此山中，云深不知处。', '隐居', '松树下问小童，说师父采药去了。就在这座山中，云雾深深不知道在哪里。', '这首诗表达了诗人对隐居生活的向往。', UNIX_TIMESTAMP()),
('宿建德江', '孟浩然', '唐', 1, '移舟泊烟渚，日暮客愁新。野旷天低树，江清月近人。', '思乡', '行船停泊在烟雾笼罩的小洲，傍晚时分增添了新的乡愁。旷野中天空显得比树还低，清澈的江水中月亮和人离得很近。', '这首诗表达了诗人的思乡之情。', UNIX_TIMESTAMP()),
('春晓', '孟浩然', '唐', 1, '春眠不觉晓，处处闻啼鸟。夜来风雨声，花落知多少。', '风景', '春天睡醒时天已经亮了，醒来时到处可以听见鸟的叫声。想起昨夜的风雨声，不知道有多少花朵被吹落了。', '这首诗表达了诗人对春天的喜爱。', UNIX_TIMESTAMP()),
('过故人庄', '孟浩然', '唐', 1, '故人具鸡黍，邀我至田家。绿树村边合，青山郭外斜。开轩面场圃，把酒话桑麻。待到重阳日，还来就菊花。', '田园', '老朋友准备了饭菜，邀请我到田家。绿树在村边环绕，青山在城外倾斜。打开窗户面对谷场菜园，端起酒杯谈论农事。等到重阳节那天，还要来欣赏菊花。', '这首诗描写了田园生活的美好。', UNIX_TIMESTAMP()),
('登鹳雀楼', '王之涣', '唐', 1, '白日依山尽，黄河入海流。欲穷千里目，更上一层楼。', '励志', '太阳靠着山峦渐渐沉落，黄河朝着大海奔流。想要看得更远，就要再登上一层楼。', '这首诗意境开阔，表达了积极向上的精神。', UNIX_TIMESTAMP()),
('凉州词', '王翰', '唐', 1, '葡萄美酒夜光杯，欲饮琵琶马上催。醉卧沙场君莫笑，古来征战几人回。', '边塞', '精美的夜光杯中盛着葡萄美酒，正要饮酒时马上的琵琶声催促。醉倒在沙场上请你不要笑，自古以来出征的人有几个能回来。', '这首诗表达了边塞将士的豪迈气概。', UNIX_TIMESTAMP()),
('出塞', '王昌龄', '唐', 1, '秦时明月汉时关，万里长征人未还。但使龙城飞将在，不教胡马度阴山。', '边塞', '秦时明月照着汉时的边关，万里长征的将士还未归还。如果有龙城飞将军李广在，绝不会让胡人的马越过阴山。', '这首诗表达了诗人对英勇将士的崇敬。', UNIX_TIMESTAMP());
